class Solution:
    def queryString(self, s, n):
        present = set()
        L = len(s)
        for i in range(L):
            for j in range(i + 1, L + 1):
                if s[i] == '1':
                    present.add(int(s[i:j], 2))
        for v in range(1, n + 1):
            if v not in present:
                return False
        return True

